+
+export interface CreateSnapshotInput {
+  id: string;
+  tenant_id: string;
+  org_id: string;
+  project_id: string;
+  env_id: string;
+  instance_id: string;
+  created_by?: string | null;
+  trigger: 'manual' | 'scheduled' | 'pre_delete' | 'pre_reset';
+  s3_bucket: string;
+  s3_key: string;
+  retention?: string;
+  expires_at?: Date;
+}
