+import { spawn } from 'child_process';
+import { Readable, PassThrough } from 'stream';
+import { Upload } from '@aws-sdk/lib-storage';
+import { GetObjectCommand } from '@aws-sdk/client-s3';
+import type { S3Client } from '@aws-sdk/client-s3';
+import { pipeline } from 'stream/promises';
+
+export interface SnapshotExecutorConfig {
+  host: string;
+  port: number;
+  username: string;
+  password: string;
+  database: string;
+}
+
+export interface SnapshotUploadTarget {
+  s3Client: S3Client;
+  bucket: string;
+  key: string;
+}
+
+export interface SnapshotResult {
+  sizeBytes: number;
+  dbSizeBytes: number;
+  pgVersion: string;
+}
+
+/**
+ * Execute pg_dump and stream output directly to S3.
+ * Returns the compressed dump size and DB metadata.
+ */
+export async function executeSnapshot(
+  dbConfig: SnapshotExecutorConfig,
+  target: SnapshotUploadTarget,
+  opts?: { timeoutMs?: number },
+): Promise<SnapshotResult> {
+  const timeoutMs = opts?.timeoutMs ?? 30 * 60 * 1000; // 30 minutes default
+
+  // Get DB size and PG version before dump
+  const [dbSizeBytes, pgVersion] = await Promise.all([
+    queryDbSize(dbConfig),
+    queryPgVersion(dbConfig),
+  ]);
+
+  const args = [
+    '--format=custom',
+    '--compress=6',
+    '--no-owner',
+    '--no-acl',
+    `--dbname=${dbConfig.database}`,
+    `--host=${dbConfig.host}`,
+    `--port=${dbConfig.port}`,
+    `--username=${dbConfig.username}`,
+  ];
+
+  const child = spawn('pg_dump', args, {
+    env: { ...process.env, PGPASSWORD: dbConfig.password },
+    stdio: ['ignore', 'pipe', 'pipe'],
+  });
+
+  let stderr = '';
+  child.stderr.on('data', (chunk: Buffer) => {
+    stderr += chunk.toString();
+  });
+
+  // Set up timeout
+  const timer = setTimeout(() => {
+    child.kill('SIGTERM');
+  }, timeoutMs);
+
+  // Stream pg_dump stdout directly to S3 multipart upload
+  const upload = new Upload({
+    client: target.s3Client,
+    params: {
+      Bucket: target.bucket,
+      Key: target.key,
+      Body: child.stdout,
+      ContentType: 'application/octet-stream',
+    },
+    queueSize: 4,
+    partSize: 10 * 1024 * 1024, // 10 MB parts
+  });
+
+  try {
+    const uploadResult = await upload.done();
+    clearTimeout(timer);
+
+    // Wait for child process to exit
+    const exitCode = await new Promise<number>((resolve, reject) => {
+      child.on('exit', (code) => resolve(code ?? 0));
+      child.on('error', reject);
+    });
+
+    if (exitCode !== 0) {
+      throw new Error(`pg_dump exited with code ${exitCode}: ${stderr.trim()}`);
+    }
+
+    // Get uploaded object size from the upload metadata
+    // If ContentLength not available, query the object
+    const sizeBytes = typeof (uploadResult as any)?.ContentLength === 'number'
+      ? (uploadResult as any).ContentLength
+      : await queryObjectSize(target);
+
+    return { sizeBytes, dbSizeBytes, pgVersion };
+  } catch (error) {
+    clearTimeout(timer);
+    child.kill('SIGTERM');
+    // Try to abort the multipart upload on failure
+    try { await upload.abort(); } catch { /* ignore */ }
+    throw error;
+  }
+}
+
+/**
+ * Execute pg_restore from an S3 snapshot into a target database.
+ */
+export async function executeRestore(
+  dbConfig: SnapshotExecutorConfig,
+  source: SnapshotUploadTarget,
+  opts?: { timeoutMs?: number },
+): Promise<void> {
+  const timeoutMs = opts?.timeoutMs ?? 30 * 60 * 1000;
+
+  // Download from S3
+  const getResult = await source.s3Client.send(
+    new GetObjectCommand({ Bucket: source.bucket, Key: source.key }),
+  );
+
+  if (!getResult.Body) {
+    throw new Error('Empty snapshot body from S3');
+  }
+
+  const args = [
+    '--format=custom',
+    '--no-owner',
+    '--no-acl',
+    '--clean',
+    '--if-exists',
+    `--dbname=${dbConfig.database}`,
+    `--host=${dbConfig.host}`,
+    `--port=${dbConfig.port}`,
+    `--username=${dbConfig.username}`,
+  ];
+
+  const child = spawn('pg_restore', args, {
+    env: { ...process.env, PGPASSWORD: dbConfig.password },
+    stdio: ['pipe', 'pipe', 'pipe'],
+  });
+
+  let stderr = '';
+  child.stderr.on('data', (chunk: Buffer) => {
+    stderr += chunk.toString();
+  });
+
+  const timer = setTimeout(() => {
+    child.kill('SIGTERM');
+  }, timeoutMs);
+
+  try {
+    // Pipe S3 stream to pg_restore stdin
+    const s3Stream = getResult.Body as Readable;
+    await pipeline(s3Stream, child.stdin);
+
+    const exitCode = await new Promise<number>((resolve, reject) => {
+      child.on('exit', (code) => resolve(code ?? 0));
+      child.on('error', reject);
+    });
+
+    clearTimeout(timer);
+
+    // pg_restore exit code 1 means "warnings" (e.g., "relation does not exist" during --clean)
+    // Only fail on exit code 2+ which indicates actual errors
+    if (exitCode > 1) {
+      throw new Error(`pg_restore exited with code ${exitCode}: ${stderr.trim()}`);
+    }
+  } catch (error) {
+    clearTimeout(timer);
+    child.kill('SIGTERM');
+    throw error;
+  }
+}
+
+/**
+ * Terminate all active connections to a database.
+ */
+export async function terminateConnections(
+  adminConfig: SnapshotExecutorConfig,
+  targetDbName: string,
+): Promise<void> {
+  const { spawn: spawnPsql } = await import('child_process');
+  const sql = `SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE datname = '${targetDbName}' AND pid <> pg_backend_pid();`;
+
+  const child = spawnPsql('psql', [
+    `--host=${adminConfig.host}`,
+    `--port=${adminConfig.port}`,
+    `--username=${adminConfig.username}`,
+    '--no-password',
+    '--command', sql,
+    adminConfig.database,
+  ], {
+    env: { ...process.env, PGPASSWORD: adminConfig.password },
+    stdio: ['ignore', 'pipe', 'pipe'],
+  });
+
+  await new Promise<void>((resolve, reject) => {
+    child.on('exit', (code) => {
+      if (code === 0) resolve();
+      else reject(new Error(`psql terminate connections exited with code ${code}`));
+    });
+    child.on('error', reject);
+  });
+}
+
+// ---------------------------------------------------------------------------
+// Internal helpers
+// ---------------------------------------------------------------------------
+
+async function queryDbSize(config: SnapshotExecutorConfig): Promise<number> {
+  return new Promise((resolve, reject) => {
+    const sql = `SELECT pg_database_size('${config.database}')::bigint AS size;`;
+    const child = spawn('psql', [
+      `--host=${config.host}`,
+      `--port=${config.port}`,
+      `--username=${config.username}`,
+      '--no-password',
+      '--tuples-only',
+      '--no-align',
+      '--command', sql,
+      config.database,
+    ], {
+      env: { ...process.env, PGPASSWORD: config.password },
+      stdio: ['ignore', 'pipe', 'pipe'],
+    });
+
+    let stdout = '';
+    child.stdout.on('data', (chunk: Buffer) => { stdout += chunk.toString(); });
+    child.on('exit', (code) => {
+      if (code !== 0) return resolve(0); // Non-critical, default to 0
+      resolve(parseInt(stdout.trim(), 10) || 0);
+    });
+    child.on('error', () => resolve(0));
+  });
+}
+
+async function queryPgVersion(config: SnapshotExecutorConfig): Promise<string> {
+  return new Promise((resolve, reject) => {
+    const child = spawn('psql', [
+      `--host=${config.host}`,
+      `--port=${config.port}`,
+      `--username=${config.username}`,
+      '--no-password',
+      '--tuples-only',
+      '--no-align',
+      '--command', 'SHOW server_version;',
+      config.database,
+    ], {
+      env: { ...process.env, PGPASSWORD: config.password },
+      stdio: ['ignore', 'pipe', 'pipe'],
+    });
+
+    let stdout = '';
+    child.stdout.on('data', (chunk: Buffer) => { stdout += chunk.toString(); });
+    child.on('exit', (code) => {
+      if (code !== 0) return resolve('unknown');
+      resolve(stdout.trim() || 'unknown');
+    });
+    child.on('error', () => resolve('unknown'));
+  });
+}
+
+async function queryObjectSize(target: SnapshotUploadTarget): Promise<number> {
+  try {
+    const { HeadObjectCommand } = await import('@aws-sdk/client-s3');
+    const head = await target.s3Client.send(
+      new HeadObjectCommand({ Bucket: target.bucket, Key: target.key }),
+    );
+    return head.ContentLength ?? 0;
+  } catch {
+    return 0;
+  }
+}

